import re

def process_line(line):
    # Split the line at '|' to ignore any distractor part
    line = line.split('|')[0].strip()
    # Use regex to find numbers in the line
    numbers = re.findall(r'-?\d+', line)
    if len(numbers) < 2:
        return 'INVALID'
    N = int(numbers[0])
    M = int(numbers[1])
    if 'apples' in line:
        return N + M
    elif 'candies' in line or 'marbles' in line:
        if M <= N:
            return N - M
        else:
            return 'INVALID'
    return 'INVALID'

if __name__ == '__main__':
    input = sys.stdin.read().strip().split('\n')
    t = int(input[0])
    results = []
    for i in range(1, t + 1):
        result = process_line(input[i])
        results.append(result)
    for result in results:
        print(result)

